def list_users(db: Session, page: int = 1, size: int = 10, role: str | None = None, is_active: bool | None = None) -> tuple[list[User], int]:
    offset = (page - 1) * size
    query = db.query(User)

    if role is not None:
        query = query.filter(User.role == role)
    if is_active is not None:
        query = query.filter(User.is_active == is_active)

    total = query.count()
    users = query.order_by(User.id).offset(offset).limit(size).all()
    return users, total
